/**
 * Media Module Public API
 *
 * Centralized exports for the Media module.
 * Import from this file when using media module functionality
 * from other parts of the application.
 *
 * @module modules/_core/media
 *
 * @example
 * ```typescript
 * import {
 *   MediaModule,
 *   MediaService,
 *   mediaRoutes,
 *   type Media,
 *   type UploadMediaRequest,
 * } from '@/modules/_core/media';
 * ```
 */

// -----------------------------------------------------------------------------
// Module Definition
// -----------------------------------------------------------------------------

export { MediaModule, default } from '@/modules/_core/media/media.module';
export type {
  MediaModuleContext,
  MediaModuleHooks,
} from '@/modules/_core/media/media.module';

// -----------------------------------------------------------------------------
// Service
// -----------------------------------------------------------------------------

export { MediaService } from '@/modules/_core/media/media.service';

// -----------------------------------------------------------------------------
// Repository
// -----------------------------------------------------------------------------

export { MediaRepository } from '@/modules/_core/media/media.repository';
export type {
  PaginatedResult,
  CreateMediaData,
  UpdateMediaData,
} from '@/modules/_core/media/media.repository';

// -----------------------------------------------------------------------------
// Controller
// -----------------------------------------------------------------------------

export { MediaController } from '@/modules/_core/media/media.controller';

// -----------------------------------------------------------------------------
// Routes
// -----------------------------------------------------------------------------

export {
  mediaRoutes,
  buildMediaApiPath,
  buildMediaAdminPath,
  isProtectedMediaRoute,
  mediaEndpoints,
  supportedFileTypes,
  getAllowedFileTypes,
} from '@/modules/_core/media/media.routes';
export type {
  MediaRouteConfig,
  MediaEndpointMetadata,
} from '@/modules/_core/media/media.routes';

// -----------------------------------------------------------------------------
// Types
// -----------------------------------------------------------------------------

// Core entity types
export type {
  Media,
  MediaWithRelations,
} from '@/modules/_core/media/media.types';

// Metadata types
export type {
  MediaMetadata,
  ImageDimensions,
  VideoMetadata,
  ProcessingMetadata,
  MediaVariant,
} from '@/modules/_core/media/media.types';

// Request/Response types
export type {
  UploadMediaRequest,
  UploadMediaResponse,
  UploadMultipleMediaRequest,
  UploadMultipleMediaResponse,
  UploadError,
  UpdateMediaRequest,
  UpdateMediaResponse,
  MediaSummary,
} from '@/modules/_core/media/media.types';

// Processing types
export type {
  ImageProcessingOptions,
  ThumbnailConfig,
  ProcessingResult,
} from '@/modules/_core/media/media.types';

// Query/Filter types
export type {
  MediaListFilters,
  MediaListParams,
} from '@/modules/_core/media/media.types';

// Event types
export type {
  MediaUploadedEvent,
  MediaDeletedEvent,
  MediaProcessedEvent,
  ThumbnailCreatedEvent,
} from '@/modules/_core/media/media.types';

// Hook context types
export type {
  BeforeUploadContext,
  AfterUploadContext,
  BeforeDeleteContext,
  AfterDeleteContext,
} from '@/modules/_core/media/media.types';

// Module settings types
export type { MediaModuleSettings } from '@/modules/_core/media/media.types';

// Storage types
export type {
  StorageConfig,
  S3Config,
} from '@/modules/_core/media/media.types';

// Type guards
export {
  isMedia,
  isImageMimeType,
  isVideoMimeType,
  isDocumentMimeType,
} from '@/modules/_core/media/media.types';

// -----------------------------------------------------------------------------
// Schemas (Zod validation)
// -----------------------------------------------------------------------------

export {
  // Constants
  ALLOWED_IMAGE_TYPES,
  ALLOWED_VIDEO_TYPES,
  ALLOWED_DOCUMENT_TYPES,
  ALLOWED_MIME_TYPES,
  MAX_FILE_SIZE,
  MAX_IMAGE_SIZE,
  MAX_VIDEO_SIZE,

  // Base schemas
  filenameSchema,
  originalNameSchema,
  mimeTypeSchema,
  altTextSchema,
  tagsSchema,
  urlSchema,
  fileSizeSchema,

  // Dimension schemas
  dimensionsSchema,

  // Metadata schemas
  videoMetadataSchema,
  processingMetadataSchema,
  mediaMetadataSchema,

  // Processing schemas
  imageProcessingOptionsSchema,

  // CRUD schemas
  uploadMediaSchema,
  updateMediaSchema,
  processMediaSchema,

  // Query schemas
  mediaListQuerySchema,
  mediaIdSchema,

  // Response schemas
  mediaResponseSchema,
  mediaSummarySchema,

  // Module settings schema
  mediaModuleSettingsSchema,

  // Utility functions
  validateFileSize,
  validateMimeType,
  getMediaTypeFromMime,
  generateUniqueFilename,
  formatFileSize,
  getExtensionFromMime,
} from '@/modules/_core/media/media.schema';

export type {
  UploadMediaInput,
  UpdateMediaInput,
  ProcessMediaInput,
  MediaListQueryInput,
  MediaIdInput,
  MediaModuleSettingsInput,
} from '@/modules/_core/media/media.schema';
